class Solution:
    def maxLengthBetweenEqualCharacters(self, s):
        best = -1
        n = len(s)
        for i in range(n):
            for j in range(n - 1, i, -1):
                if s[i] == s[j]:
                    gap = j - i - 1
                    if gap > best:
                        best = gap
                    break
        return best

