class Solution:
    def maxLengthBetweenEqualCharacters(self, s: str) -> int:
        first_seen = {}
        best = -1
        for i, ch in enumerate(s):
            if ch in first_seen:
                best = max(best, i - first_seen[ch] - 1)
            else:
                first_seen[ch] = i
        return best

