var maxLengthBetweenEqualCharacters = function(s) {
    const firstSeen = new Map();
    let best = -1;
    for (let i = 0; i < s.length; i++) {
        const ch = s[i];
        if (firstSeen.has(ch)) {
            best = Math.max(best, i - firstSeen.get(ch) - 1);
        } else {
            firstSeen.set(ch, i);
        }
    }
    return best;
};
